[[inputs.http_listener_v2]]
    service_address = "tcp://:19090"
    paths = ["/telegraf/api"]
    methods = ["POST"]
    data_format = "influx"
    http_success_code = 204
    read_timeout = "10s"
    write_timeout = "10s"
    max_body_size = "20MB"

[[inputs.netflow]]
    service_address = "udp://:2055"

[[inputs.sflow]]
    service_address = "udp://:6343"

[[processors.starlark]]
    source = '''
load("json.star", "json")


def _flow_asset_map_json():
    if flow_asset_map_json == "" or flow_asset_map_json == "$" + "{FLOW_ASSET_MAP_JSON}":
        return "{}"
    return flow_asset_map_json


FLOW_ASSET_MAP = json.decode(_flow_asset_map_json())
FLOW_DEVICE_IP_FIELDS = ["device_ip", "source_ip", "agent_address", "src_addr", "source", "exporter_ip"]
FLOW_SAMPLING_FIELDS = ["SAMPLING_INTERVAL", "SAMPLING_ALGORITHM", "sampling_rate", "samplingRate"]


def _value(metric, key):
    if key in metric.tags:
        return metric.tags[key]
    if key in metric.fields:
        return metric.fields[key]
    return None


def _collect_type(metric):
    if "collect_type" in metric.tags:
        value = metric.tags["collect_type"]
        if value == "netflow" or value == "sflow":
            return value
    if metric.name == "netflow" or metric.name == "sflow":
        return metric.name
    if "netflow" in metric.name:
        return "netflow"
    if "sflow" in metric.name:
        return "sflow"
    return None


def _device_ip(metric):
    for key in FLOW_DEVICE_IP_FIELDS:
        value = _value(metric, key)
        if value != None and value != "":
            return value
    return None


def _parse_rate(value):
    if value == None or value == "":
        return None
    err = catch(lambda: int(value))
    if err != None:
        return None
    rate = int(value)
    if rate < 0:
        return None
    return rate


def _effective_sampling_rate(metric, fallback_sampling_rate):
    for key in FLOW_SAMPLING_FIELDS:
        rate = _parse_rate(_value(metric, key))
        if rate != None:
            return rate
    return fallback_sampling_rate


def apply(metric):
    collect_type = _collect_type(metric)
    if collect_type == None:
        return metric

    device_ip = _device_ip(metric)
    if device_ip == None:
        return metric

    asset = FLOW_ASSET_MAP.get(str(cloud_region_id) + ":" + str(device_ip))
    if asset == None:
        return metric

    protocols = asset.get("protocols")
    if protocols != None and collect_type not in protocols:
        return metric

    fallback_sampling_rate = _parse_rate(asset.get("fallback_sampling_rate"))
    metric.tags["instance_id"] = str(asset.get("instance_id"))
    metric.tags["instance_type"] = str(asset.get("instance_type"))
    metric.tags["collect_type"] = collect_type

    if fallback_sampling_rate != None:
        metric.tags["fallback_sampling_rate"] = str(fallback_sampling_rate)

    effective_sampling_rate = _effective_sampling_rate(metric, fallback_sampling_rate)
    if effective_sampling_rate != None:
        metric.tags["effective_sampling_rate"] = str(effective_sampling_rate)

    return metric
'''

    [processors.starlark.constants]
        cloud_region_id = "${node.cloud_region}"
        flow_asset_map_json = '${FLOW_ASSET_MAP_JSON}'

